mapper.select:
SELECT
CONCAT(vb.brand, '-', vbi.vehicle_model) AS vehicle_model_info,
CONCAT(vb.brand_en, '-', vbi.vehicle_model) AS vehicle_model_info,
vbi.id id, vbi.vehicle_system_version as vehicle_system_version, vbi.test_date as test_date, AVG(vdt.calculate_score) AS avg_score FROM vehicle_base_info vbi LEFT JOIN vehicle_brand vb ON vbi.brand_id = vb.id LEFT JOIN vehicle_domain_tree vdt ON vdt.vehicle_base_id = vbi.id LEFT JOIN vehicle_domain_index vdi ON vdi.id = vdt.domain_index_id left join vehicle_functional_domain vfd on vfd.id = vdi.functional_domain LEFT JOIN vehicle_domain_tag vdtg on vdtg.functional_domain_id = vfd.id WHERE vdi.functional_domain = #{functionDomainId}
AND vbi.id IN
#{id}
and vdtg.tag_name = #{domainTagName} GROUP BY vbi.id,
vb.brand,
vb.brand_en,
vbi.vehicle_model,vbi.vehicle_system_version,vbi.test_date;

SELECT vbi.id , vbi.vehicle_system_version as vehicle_system_version, vbi.test_date as test_date, CONCAT(vb.brand, '-', vbi.vehicle_model) AS vehicle_model_info, AVG(vdt.calculate_score) AS avg_score FROM vehicle_base_info vbi LEFT JOIN vehicle_brand vb ON vbi.brand_id = vb.id LEFT JOIN vehicle_domain_tree vdt ON vdt.vehicle_base_id = vbi.id LEFT JOIN vehicle_domain_index vdi ON vdi.id = vdt.domain_index_id LEFT JOIN vehicle_domain_tag vdtg on vdtg.functional_domain_id = vdi.functional_domain WHERE vdtg.tag_name =#{domainTagName} and vdt.calculate_score>0
and vbi.id IN
#{id}
GROUP BY vbi.id, vb.brand, vbi.vehicle_model,vbi.vehicle_system_version,vbi.test_date;
